using System; using System.Linq; using System.Data.Entity; using System.Windows; using System.Windows.Controls; using WarehouseManagement.ApplicationData;
namespace WarehouseManagement.Pages { public partial class ShipmentsPage:Page { public ShipmentsPage(){InitializeComponent(); Load();} void Load(){lvOrders.ItemsSource=AppConnect.model01.Shipments.Include("Clients").ToList().Select(x=>new{OrderID=x.ShipmentID,UserFullName=x.Clients.ClientName,OrderDate=x.ShipmentDate,TotalAmount=x.ShipmentItems.Sum(i=>i.Quantity*i.UnitPrice),StatusName=x.ShipmentNumber});} private void btnBack_Click(object s,RoutedEventArgs e){AppFrame.frmMain.GoBack();} private void btnRefresh_Click(object s,RoutedEventArgs e){Load();} private void btnOpenDetails_Click(object s,RoutedEventArgs e){if(lvOrders.SelectedItem!=null) MessageBox.Show("Детальная информация доступна в списке позиций отгрузки");} private void btnCancelOrder_Click(object s,RoutedEventArgs e){MessageBox.Show("Удаление проведённых отгрузок запрещено правилами учета");}}}
